import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Mic, MicOff, Phone, PhoneOff, Volume2, VolumeX, Clock, User, Bot } from 'lucide-react';

interface TranscriptEntry {
  id: string;
  speaker: 'STUDENT' | 'AI_INTERVIEWER';
  message: string;
  timestamp: string;
}

const VoiceInterview: React.FC = () => {
  const { interviewId, agentId } = useParams<{ interviewId?: string; agentId?: string }>();
  const navigate = useNavigate();
  const { state: authState } = useAuth();

  const [isConnected, setIsConnected] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [transcript, setTranscript] = useState<TranscriptEntry[]>([]);
  const [elapsedTime, setElapsedTime] = useState(0);
  const [sessionType, setSessionType] = useState<'interview' | 'practice'>('interview');
  const [sessionStarted, setSessionStarted] = useState(false);

  const websocketRef = useRef<WebSocket | null>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    // Determine session type based on URL parameters
    if (agentId) {
      setSessionType('practice');
    } else if (interviewId) {
      setSessionType('interview');
    }

    if (interviewId || agentId) {
      initializeSession();
    }

    return () => {
      cleanup();
    };
  }, [interviewId, agentId]);

  // Timer effect
  useEffect(() => {
    if (isRecording) {
      timerRef.current = setInterval(() => {
        setElapsedTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }

    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [isRecording]);

  const initializeSession = async () => {
    try {
      const sessionId = interviewId || agentId;
      const wsUrl = `ws://localhost:8000/ws/${sessionId}`;
      websocketRef.current = new WebSocket(wsUrl);

              websocketRef.current.onopen = () => {
          console.log('WebSocket connected');
          setIsConnected(true);

          websocketRef.current?.send(JSON.stringify({
            type: 'join_session',
            participant_id: authState.user?.id,
            participant_name: `${authState.user?.first_name} ${authState.user?.last_name}`,
            role: 'student',
            session_type: sessionType
          }));
        };

      websocketRef.current.onmessage = (event) => {
        const data = JSON.parse(event.data);
        handleWebSocketMessage(data);
      };

      websocketRef.current.onerror = (error) => {
        console.error('WebSocket error:', error);
        setIsConnected(false);
      };

    } catch (error) {
      console.error('Error initializing session:', error);
    }
  };

  const handleWebSocketMessage = (data: any) => {
    switch (data.type) {
      case 'session_ready':
        console.log('Session ready:', data);
        // Session is ready, add welcome messages
        setTimeout(() => {
          const welcomeMessages = generateWelcomeMessages();
          setTranscript(welcomeMessages);
          setSessionStarted(true);
        }, 500);
        break;
      case 'transcript_update':
        setTranscript(prev => [...prev, data.entry]);
        break;
      case 'ai_response':
        // Handle AI response
        console.log('AI response:', data);
        break;
      case 'session_ended':
        console.log('Session ended:', data);
        navigate('/dashboard');
        break;
      default:
        console.log('Unknown message type:', data.type);
    }
  };

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaRecorderRef.current = new MediaRecorder(stream);

      mediaRecorderRef.current.ondataavailable = (event) => {
        if (event.data.size > 0 && websocketRef.current) {
          const sessionId = interviewId || agentId;
          websocketRef.current.send(JSON.stringify({
            type: 'audio_data',
            session_id: sessionId,
            audio_data: event.data
          }));
        }
      };

      mediaRecorderRef.current.start(1000);
      setIsRecording(true);
      setElapsedTime(0); // Reset timer when starting

    } catch (error) {
      console.error('Error starting recording:', error);
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
      setIsRecording(false);
    }
  };

  const toggleMute = () => {
    setIsMuted(!isMuted);
  };

  const endSession = async () => {
    stopRecording();

    if (websocketRef.current) {
      websocketRef.current.send(JSON.stringify({
        type: 'end_session'
      }));
    }

    navigate('/dashboard');
  };

  const cleanup = () => {
    stopRecording();
    if (websocketRef.current) {
      websocketRef.current.close();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const generateWelcomeMessages = () => {
    const messages = [];

    if (sessionType === 'interview') {
      messages.push({
        id: 'welcome-1',
        speaker: 'AI_INTERVIEWER' as const,
        message: "Hello! I'm your AI interviewer, here to help you prepare for real interviews. Let's get started. First, could you please introduce yourself?",
        timestamp: new Date().toISOString()
      });
      messages.push({
        id: 'welcome-2',
        speaker: 'AI_INTERVIEWER' as const,
        message: "🧠 Custom context: I'll be asking behavioral and technical questions based on your field.",
        timestamp: new Date().toISOString()
      });
      messages.push({
        id: 'welcome-3',
        speaker: 'AI_INTERVIEWER' as const,
        message: "🧭 Interview Type: This session will simulate a 30-minute technical interview. You can stop anytime.",
        timestamp: new Date().toISOString()
      });
    } else {
      messages.push({
        id: 'welcome-1',
        speaker: 'AI_INTERVIEWER' as const,
        message: "Hello! I'm your AI practice partner, here to help you improve your interview skills. Let's have a conversation!",
        timestamp: new Date().toISOString()
      });
      messages.push({
        id: 'welcome-2',
        speaker: 'AI_INTERVIEWER' as const,
        message: "🧠 Custom context: I'll be asking behavioral and technical questions based on your field.",
        timestamp: new Date().toISOString()
      });
      messages.push({
        id: 'welcome-3',
        speaker: 'AI_INTERVIEWER' as const,
        message: "📊 Real-time feedback: I'll also give you quick tips after each answer to help you improve.",
        timestamp: new Date().toISOString()
      });
    }

    return messages;
  };

  return (
    <div className="min-h-screen bg-gray-50 p-6">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">
                {sessionType === 'practice' ? 'Practice Session' : 'Voice Interview'}
              </h1>
              <p className="text-gray-600">
                {sessionType === 'practice' 
                  ? 'Free-form practice with AI agent' 
                  : 'Real-time AI-powered interview session'
                }
              </p>
            </div>
                      <div className="flex items-center space-x-4">
            <div className="flex items-center space-x-2">
              <Clock className="w-5 h-5 text-gray-500" />
              <span className="text-lg font-mono">{formatTime(elapsedTime)}</span>
            </div>
            <div className={`flex items-center space-x-2 ${isConnected ? 'text-green-600' : 'text-red-600'}`}>
              <div className={`w-3 h-3 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`}></div>
              <span className="font-medium">{isConnected ? 'Connected' : 'Disconnected'}</span>
            </div>
            {sessionStarted && (
              <div className="flex items-center space-x-2 text-blue-600">
                <div className="w-3 h-3 rounded-full bg-blue-500 animate-pulse"></div>
                <span className="font-medium">Session Active</span>
              </div>
            )}
          </div>
          </div>
        </div>

        {/* Controls */}
        <div className="bg-white rounded-lg shadow-sm p-6 mb-6">
          <div className="flex items-center justify-center space-x-4">
            <button
              onClick={isRecording ? stopRecording : startRecording}
              className={`p-4 rounded-full ${
                isRecording 
                  ? 'bg-red-500 hover:bg-red-600 text-white' 
                  : 'bg-green-500 hover:bg-green-600 text-white'
              }`}
            >
              {isRecording ? <MicOff className="w-6 h-6" /> : <Mic className="w-6 h-6" />}
            </button>

            <button
              onClick={toggleMute}
              className={`p-4 rounded-full ${
                isMuted ? 'bg-gray-500 hover:bg-gray-600' : 'bg-blue-500 hover:bg-blue-600'
              } text-white`}
            >
              {isMuted ? <VolumeX className="w-6 h-6" /> : <Volume2 className="w-6 h-6" />}
            </button>

            <button
              onClick={endSession}
              className="p-4 rounded-full bg-red-500 hover:bg-red-600 text-white"
            >
              <PhoneOff className="w-6 h-6" />
            </button>
          </div>

          <div className="mt-4 text-center">
            <p className="text-sm text-gray-600">
              {!sessionStarted ? 'Connecting to AI interviewer...' : 
               isRecording ? 'Recording... Speak clearly into your microphone' : 
               'Click the microphone to start speaking with the AI'}
            </p>
            {sessionStarted && !isRecording && (
              <p className="text-xs text-gray-500 mt-1">
                The AI interviewer is ready to start the conversation
              </p>
            )}
          </div>
        </div>

        {/* Transcript */}
        <div className="bg-white rounded-lg shadow-sm p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Live Transcript</h3>

          <div className="space-y-4 max-h-96 overflow-y-auto">
            {transcript.map((entry) => (
              <div
                key={entry.id}
                className={`flex items-start space-x-3 ${
                  entry.speaker === 'STUDENT' ? 'justify-end' : 'justify-start'
                }`}
              >
                {entry.speaker === 'AI_INTERVIEWER' && (
                  <div className="w-8 h-8 bg-blue-500 rounded-full flex items-center justify-center">
                    <Bot className="w-4 h-4 text-white" />
                  </div>
                )}

                <div className={`max-w-xs lg:max-w-md p-3 rounded-lg ${
                  entry.speaker === 'STUDENT' 
                    ? 'bg-blue-500 text-white' 
                    : 'bg-gray-100 text-gray-900'
                }`}>
                  <p className="text-sm">{entry.message}</p>
                  <p className="text-xs opacity-75 mt-1">
                    {new Date(entry.timestamp).toLocaleTimeString()}
                  </p>
                </div>

                {entry.speaker === 'STUDENT' && (
                  <div className="w-8 h-8 bg-green-500 rounded-full flex items-center justify-center">
                    <User className="w-4 h-4 text-white" />
                  </div>
                )}
              </div>
            ))}

            {transcript.length === 0 && (
              <div className="text-center text-gray-500 py-8">
                {!sessionStarted ? (
                  <div>
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-4"></div>
                    <p>Connecting to AI interviewer...</p>
                  </div>
                ) : (
                  <p>No transcript available yet. Start speaking to see the conversation.</p>
                )}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default VoiceInterview;
